INSERT INTO public.system_settings (key, value)
VALUES ('system_policy', '{
  "content": "# CHINH SACH HE THONG TEAMWORKS UEH\n\n**Phien ban:** 1.0 | **Ngay hieu luc:** 08/03/2026\n\n---\n\n## 1. GIOI THIEU & PHAM VI AP DUNG\n\n### 1.1 Gioi thieu\nTeamworks UEH la nen tang quan ly cong viec nhom truc tuyen danh rieng cho sinh vien Dai hoc Kinh te TP. Ho Chi Minh (UEH). He thong ho tro viec phan cong, theo doi tien do, cham diem qua trinh va luu tru tai lieu du an.\n\n### 1.2 Pham vi ap dung\nChinh sach nay ap dung cho **tat ca nguoi dung** bao gom:\n- Quan tri vien (Admin)\n- Thanh vien Nang cao (Leader)\n- Thanh vien (Member)\n\nBang viec dang ky va su dung he thong, nguoi dung **dong y tuan thu** toan bo chinh sach nay.\n\n---\n\n## 2. TAI KHOAN & XAC THUC\n\n### 2.1 Dang ky tai khoan\n- Yeu cau: Email UEH, Ma so sinh vien (MSSV), Ho ten day du\n- Tai khoan sau khi dang ky can duoc **Admin duyet** truoc khi su dung\n- Moi MSSV chi duoc dang ky **mot tai khoan duy nhat**\n\n### 2.2 Bao mat tai khoan\n- Mat khau toi thieu **6 ky tu**\n- Tai khoan duoc Leader tao se yeu cau **doi mat khau lan dau dang nhap**\n- **Nghiem cam** chia se tai khoan cho nguoi khac\n- Nguoi dung chiu **toan bo trach nhiem** voi moi hanh dong thuc hien tren tai khoan cua minh\n\n### 2.3 Khoi phuc mat khau\n- Su dung chuc nang \"Quen mat khau\" tren trang dang nhap\n- Ma xac nhan (OTP) se duoc gui qua email dang ky\n- Ma OTP co hieu luc trong thoi gian gioi han\n\n---\n\n## 3. VAI TRO & QUYEN HAN\n\n### 3.1 Quan tri vien (Admin)\n- Quan ly toan bo he thong: nguoi dung, du an, cai dat\n- Duyet/tu choi tai khoan dang ky\n- Tam dinh chi tai khoan vi pham\n- Quan ly sao luu va bao tri he thong\n- Xem nhat ky hoat dong toan he thong\n- Khong bi gioi han dung luong luu tru\n\n### 3.2 Thanh vien Nang cao (Leader)\n- Tao va quan ly du an nhom\n- Tao giai doan (Stages) va cong viec (Tasks)\n- Phan cong thanh vien vao tasks\n- Cham diem qua trinh cho thanh vien\n- Quan ly tai nguyen du an (files, links)\n- Them/xoa thanh vien trong du an\n- Xuat bao cao minh chung PDF\n\n### 3.3 Thanh vien (Member)\n- Xem tasks duoc phan cong\n- Nop bai (file hoac link) theo deadline\n- Xem diem qua trinh cua ban than\n- Gui khieu nai diem (Appeal)\n- Tham gia hop truc tuyen\n- Binh luan va trao doi trong du an\n\n---\n\n## 4. QUY TAC SU DUNG DU AN\n\n### 4.1 Noi dung\n- Noi dung du an phai **phu hop** voi muc dich hoc tap\n- **Nghiem cam** noi dung: xuc pham, spam, quang cao, vi pham ban quyen\n- Leader chiu trach nhiem voi noi dung du an cua minh\n\n### 4.2 Deadline & Nop bai\n- Thanh vien phai nop bai **truoc deadline** duoc thiet lap\n- Nop tre se bi **tru diem tu dong** theo cong thuc he thong\n- Leader co the gia han deadline trong truong hop dac biet\n- Nop bai ho tro 2 hinh thuc: **Upload file** hoac **Nop link**\n\n### 4.3 Gioi han file\n- Kich thuoc file toi da theo cai dat cua tung task\n- Dinh dang file phai phu hop voi yeu cau task\n\n---\n\n## 5. LUU TRU & DUNG LUONG\n\n### 5.1 Han muc luu tru\n- Moi nguoi dung duoc cap **200MB** dung luong luu tru mac dinh\n- Admin co the dieu chinh han muc cho tung nguoi dung\n- Quan tri vien (Admin) **khong bi gioi han** dung luong\n\n### 5.2 Vuot han muc\n- Khi vuot 200MB, nguoi dung **chi co the nop bai bang link**\n- Khong the upload file moi cho den khi dung luong duoc giai phong\n- Lien he Admin de yeu cau tang han muc neu can thiet\n\n---\n\n## 6. CHAM DIEM & KHIEU NAI\n\n### 6.1 He thong cham diem\n- Diem duoc tinh dua tren **dong gop thuc te** cho tung task\n- Cac yeu to anh huong diem:\n  - **Diem co ban (Base Score):** 0-10 diem\n  - **He so K:** Dieu chinh theo muc do hoan thanh tong the\n  - **Phat tre han (Late Penalty):** Tru diem khi nop muon\n  - **Phat review (Review Penalty):** Tru khi bi yeu cau sua nhieu lan\n  - **Bonus nop som (Early Bonus):** Cong diem khi nop truoc han\n  - **Bonus Bug Hunter:** Cong diem khi phat hien loi\n\n### 6.2 Diem giai doan & Diem tong ket\n- Diem giai doan = Trung binh diem task trong giai doan x He so K\n- Diem tong ket = Trung binh co trong cua cac giai doan\n- Leader co the dieu chinh diem voi ly do ro rang\n\n### 6.3 Khieu nai diem (Appeal)\n- Thanh vien co quyen **khieu nai** diem task hoac diem giai doan\n- Yeu cau khieu nai phai kem **ly do cu the** va minh chung\n- Leader/Admin se xem xet va phan hoi khieu nai\n- Ket qua khieu nai: Chap nhan / Tu choi (co phan hoi)\n\n---\n\n## 7. TAM DINH CHI & VI PHAM\n\n### 7.1 Cac hanh vi vi pham\n- Su dung tai khoan nguoi khac\n- Dang tai noi dung khong phu hop\n- Spam he thong (tao du an/task vo nghia)\n- Co tinh pha hoai du an cua nguoi khac\n- Lam dung chuc nang khieu nai\n- Vi pham quy che hoc tap cua UEH\n\n### 7.2 Hinh thuc xu ly\n- **Canh cao:** Thong bao qua he thong\n- **Tam dinh chi 1 gio - 24 gio:** Vi pham nhe\n- **Tam dinh chi 1 ngay - 7 ngay:** Vi pham trung binh\n- **Tam dinh chi 30 ngay:** Vi pham nghiem trong\n- **Tam dinh chi vinh vien:** Vi pham dac biet nghiem trong\n\n### 7.3 Trong thoi gian bi dinh chi\n- Khong the dang nhap vao he thong\n- Hien thi man hinh thong bao ly do va thoi gian het han\n- Sau khi het han, tai khoan tu dong mo khoa\n\n---\n\n## 8. BAO TRI HE THONG\n\n### 8.1 Quyen bao tri\n- Chi Admin co quyen bat/tat **che do bao tri**\n- Khi bat bao tri, toan bo nguoi dung (tru Admin) se thay **man hinh bao tri**\n\n### 8.2 Thong bao\n- Admin thiet lap **thong bao bao tri** truoc khi thuc hien\n- Thong bao bao gom: ly do, thoi gian du kien hoan thanh\n\n---\n\n## 9. QUYEN RIENG TU & DU LIEU\n\n### 9.1 Bao ve du lieu\n- Du lieu nguoi dung duoc bao ve boi **chinh sach truy cap nghiem nhat**\n- Nguoi dung chi xem duoc du lieu cua du an ma minh tham gia\n- Thong tin ca nhan chi hien thi cho thanh vien cung du an\n\n### 9.2 Chia se cong khai\n- Leader co the bat/tat **che do cong khai** cho du an\n- Khi cong khai, nguoi ngoai co the xem: danh sach thanh vien, tasks, tai nguyen, nhat ky\n- Thong tin nhay cam (diem so, tin nhan) **khong bao gio** duoc cong khai\n\n### 9.3 Ho so cong khai\n- Nguoi dung co the tao **username** de co trang ho so cong khai\n- Ho so cong khai hien thi: ten, bio, ky nang, thanh tuu\n- Khong bat buoc - chi khi nguoi dung tu thiet lap\n\n---\n\n## 10. DIEU KHOAN CUOI\n\n### 10.1 Cap nhat chinh sach\n- Admin co quyen **cap nhat chinh sach** bat ky luc nao\n- Nguoi dung se duoc thong bao khi co thay doi quan trong\n- Phien ban va ngay hieu luc duoc ghi ro o dau chinh sach\n\n### 10.2 Dong y\n- Viec tiep tuc su dung he thong sau khi chinh sach duoc cap nhat dong nghia voi viec **dong y chinh sach moi**\n- Neu khong dong y, nguoi dung co quyen ngung su dung he thong\n\n---\n\n*© 2025-2026 Teamworks UEH - Dai hoc Kinh te TP. Ho Chi Minh*"
}'::jsonb)
ON CONFLICT ON CONSTRAINT system_settings_key_key DO UPDATE
SET value = EXCLUDED.value, updated_at = now();